('SYSJ0132', '{\"full-name\":\"Joudy Alaa\",\"email-address\":\"joudy.a.m.y@gmail.com\",\"contact-number\":\"+201122674022\",\"country\":\"Egypt\",\"gender\":\"female\",\"birth-date\":\"2008-09-11\",\"institution\":\"Maadi STEM School for Girls \",\"grade-year\":\"11\",\"gpa\":\"3.7\",\"interest\":[\"Physics & Astrophysics\"],\"interest_ratings\":{\"Physics & Astrophysics\":\"9\"},\"grade-previous\":\"\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours_commitment\":\"8\",\"time_blocks\":\"At the first of August I have a competition that I am ambassador at so I will guide them throughout.\",\"hear_about\":\"Friend\"}', '{\"research_files\":[{\"name\":\"Dark Matter.MinervaResearch.pdf\",\"path\":\"uploads\\/SYSJ0132\\/drafts\\/Dark_Matter.MinervaResearch.pdf\",\"size\":130386,\"type\":\"application\\/pdf\"}]}', '2025-06-28 02:03:38'),
('SYSJ0134', '{\"full-name\":\"Alkasem Soliman Mohamed\",\"email-address\":\"alkasemsoliman13@gmail.com\",\"contact-number\":\"01104415914\",\"country\":\"Egypt\",\"gender\":\"male\",\"birth-date\":\"2009-07-18\",\"institution\":\"STEM UNIT\",\"grade-year\":\"G:10\",\"gpa\":\"3.87\",\"interest\":[\"Computer Science,Engineering (not Aerospace Engineering),Mathematics\"],\"interest_ratings\":{\"Computer Science\":\"10\",\"Engineering (not Aerospace Engineering)\":\"8\",\"Mathematics\":\"9\"},\"grade-previous\":\"mathmatics: A  mechanics: b+ , cmputer science: b+\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '[]', '2025-06-21 11:17:10'),
('SYSJ0135', '{\"full-name\":\"Haneen ahmed shalaby\",\"email-address\":\"haneenmo043@gmail.com\",\"contact-number\":\"+201551454999\",\"country\":\"Egypt\",\"gender\":\"female\",\"birth-date\":\"2009-08-21\",\"institution\":\"Alexandria STEM School\",\"grade-year\":\"Grade 10\",\"gpa\":\"3.6\\\\4.0\",\"interest\":[\"Mathematics,Philosophy,Physics & Astrophysics\"],\"interest_ratings\":{\"Mathematics\":\"6\",\"Philosophy\":\"5\",\"Physics & Astrophysics\":\"10\"},\"grade-previous\":\"Physics: B+ , Mathematics: B+, Philosophy: Not a subject in my curriculum \",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '[]', '2025-06-20 20:47:38'),
('SYSJ0136', '{\"full-name\":\"malak mohamed abd elghany \",\"email-address\":\"jsygyfgsioshsoshsucu@gmail.com\",\"contact-number\":\"01030224631\",\"country\":\"Egypt\",\"gender\":\"female\",\"birth-date\":\"2008-10-10\",\"institution\":\"cairo\",\"grade-year\":\"11\",\"gpa\":\"3.7\",\"interest\":[\"Biology\"],\"interest_ratings\":{\"Biology\":\"5\"},\"grade-previous\":\"4 GPA in grade 9 ,3.7 GPA in grade 10\",\"first-essay\":\"As for me, I have experience in scientific research. I began my high school studies in STEM schools, which are schools that rely on scientific research by creating projects based on scientific principles. To find a solution to a problem, one must first identify the problem, its root causes, and then find a solution. I have also joined many teams that conduct scientific research, including i y n a. I d a research project in the field of neuroscience. Initially, before conducting any scientific research, I faced many difficulties regarding the scientific approach I should follow. After asking my friends who have experience in the field of research and some of my teachers, and conducting extensive research, I must follow certain steps, including the steps of the engineering design process (EDP). Scientific Research Steps:\\r\\n\\r\\nChoosing a Research Topic\\r\\n\\r\\nFormulating the Research Problem or Question\\r\\n\\r\\nReviewing Previous Studies\\r\\n\\r\\nDefining Research Objectives\\r\\n\\r\\nFormulating Hypotheses\\r\\n\\r\\nChoosing the Appropriate Scientific Method\\r\\n\\r\\nCollecting Data\\r\\n\\r\\nAnalysis of Data\\r\\n\\r\\nInterpreting Results\\r\\n\\r\\nWriting a Report or Scientific Research\\r\\nI have also helped my friends who are inexperienced follow these steps.\\r\\nOne of the most important pieces of advice I have given them is to verify the accuracy of the information. For accurate, comprehensive research that contains reliable information, it is essential to verify the information from more than one source.\",\"second-essay\":\"Hello, Team 123.\\r\\n\\r\\nI hope you are all well. I noticed that you did not submit your research proposal by the deadline, which is essential for us to progress on the project schedule.\\r\\n\\r\\nI appreciate your efforts, and I understand that sometimes circumstances arise beyond our control. However, it is very important to adhere to deadlines, so I ask that you complete and submit your proposal within 24 hours at most.\\r\\n\\r\\nFailure to meet this deadline will result in a formal warning for the team.\\r\\n\\r\\nAccording to our established system:\\r\\nIf three warnings accumulate, the team will be permanently removed from the project.\\r\\n\\r\\nIf you are experiencing difficulties or need support or guidance, please do not hesitate to contact me immediately.\\r\\n\\r\\nI am here to help you, and your success is the success of the entire team.\\r\\n\\r\\nI look forward to your response and an  as soon as possible.\\r\\n\\r\\nRegards,\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '[]', '2025-06-20 21:38:19'),
('SYSJ0140', '{\"full-name\":\"Mohammed Mohammed Yousuf Abd Al-Razik\",\"email-address\":\"mohammed.mo.alqabbani@gmail.com\",\"contact-number\":\"+201110008687\",\"country\":\"Egypt\",\"gender\":\"male\",\"birth-date\":\"2009-05-14\",\"institution\":\"Al-Orman Secondary School for Boys \",\"grade-year\":\"11\",\"gpa\":\"4\",\"interest\":[\"\"],\"grade-previous\":\"In science: 100%. \\u060c in Math: 96.5%\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '[]', '2025-06-20 22:29:25'),
