('SYSJ0174', '{\"full-name\":\"vincent yuan\",\"email-address\":\"vincenty72000@gmail.com\",\"contact-number\":\"3472809828\",\"country\":\"United States\",\"birth-date\":\"2010-07-21\",\"institution\":\"Arizona State University \",\"grade-year\":\"2025\",\"gpa\":\"4\",\"interest\":[\"Biology,Business, Entrepreneurship, & Strategy,Environmental Science,Medicine & Public Health,Neuroscience & Neurobiology,Psychology\"],\"interest_ratings\":{\"Biology\":\"5\",\"Business, Entrepreneurship, & Strategy\":\"8\",\"Environmental Science\":\"7\",\"Medicine & Public Health\":\"9\",\"Neuroscience & Neurobiology\":\"7\",\"Psychology\":\"6\"},\"grade-previous\":\"4.0\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '[]', '2025-06-22 02:15:49'),
('SYSJ0175', '{\"full-name\":\"Roba Ahmed\",\"email-address\":\"roba2020ahmed@gmail.com\",\"contact-number\":\"+201027209247\",\"country\":\"Egypt \",\"gender\":\"female\",\"birth-date\":\"2010-01-05\",\"institution\":\"Ali bin abi Taleb prep school \",\"grade-year\":\"Grade 9\",\"gpa\":\"3.58\",\"interest\":[\"\"],\"grade-previous\":\"\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '[]', '2025-06-22 07:34:11'),
('SYSJ0176', '{\"full-name\":\"\",\"email-address\":\"\",\"contact-number\":\"\",\"country\":\"\",\"gender\":\"male\",\"birth-date\":\"\",\"institution\":\"\",\"grade-year\":\"\",\"gpa\":\"\",\"interest\":[\"\"],\"grade-previous\":\"\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '[]', '2025-06-22 07:26:02'),
('SYSJ0177', '{\"full-name\":\"Kerollos Mikhail Awad Ibrahim \",\"email-address\":\"keromeca345@gmail.com\",\"contact-number\":\"01229668441\",\"country\":\"Egypt\",\"gender\":\"male\",\"birth-date\":\"2008-05-01\",\"institution\":\"Kafr elmansora official language school \",\"grade-year\":\"\",\"gpa\":\"\",\"interest\":[\"\"],\"grade-previous\":\"\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '[]', '2025-06-22 07:35:30'),
('SYSJ0178', '{\"full-name\":\"Zainab Mahmoud\",\"email-address\":\"hmmansour87@gmail.com\",\"contact-number\":\"+201129399526\",\"country\":\"Egypt\",\"gender\":\"female\",\"birth-date\":\"2008-06-23\",\"institution\":\"Maadi STEM High School for Girls \",\"grade-year\":\"11\",\"gpa\":\"4.0\\/4.0\",\"interest\":[\"Biology,Computer Science,Environmental Science\"],\"interest_ratings\":{\"Biology\":\"9\",\"Computer Science\":\"8\",\"Environmental Science\":\"8\"},\"grade-previous\":\"Biology- A , Computer-A\",\"first-essay\":\"Mentorship in scientific research is akin to guiding a ship through uncharted waters it requires not only a deep understanding of the scientific landscape but also the ability to inspire and navigate students through the complexities they encounter. As I aspire to be a research mentor at YSJ, I am reminded of how pivotal guidance can ignite a scholar\\u2019s journey from curiosity to innovation. My path, characterized by diverse research endeavors and leadership roles, has prepared me to meet YSJ\\u2019s high standards and contribute to the next generation of scientific leaders.\\r\\n\\r\\nThe quote underscores the dual role of a mentor: to possess comprehensive knowledge and to motivate students through challenges. This duality is reflected in my experiences, such as leading the Content Writing Committee at STEM MUN, where I nurtured new talents in STEM through strategic guidance and encouragement. Moreover, my participation in the IYRC STEM Winter Program, where I developed a proposal on using machine learning for non-invasive skin cancer diagnostics, exemplifies my commitment to pioneering research that addresses real-world issues.\\r\\n\\r\\nAt YSJ, I envision directing young researchers toward their potential by leveraging these experiences. The program\\u2019s emphasis on global challenges resonates with my work at the Climate Science Olympiad, where I crafted innovative solutions to food insecurity. Such experiences have equipped me to help learners overcome complex scientific problems, as demonstrated in my leadership of the AI Club, where I guided peers through intricate AI projects.\\r\\n\\r\\nYSJ\\u2019s vibrant research community aligns with my academic and mentoring goals. I am eager to inspire students, fostering an environment where their scientific curiosity can flourish and lead to groundbreaking discoveries. Together, we can transform challenges into opportunities for growth and innovation.\",\"second-essay\":\"Hi Team 123,\\r\\n\\r\\nI hope you\\u2019re all doing well! I wanted to touch base regarding our Research Idea Proposal. This proposal is a key component in our program, representing your hard work and innovative spirit. Completing it is essential for not just our project but also for your progression and success in the program.\\r\\n\\r\\nI know balancing responsibilities can be tough, but I have immense confidence in your abilities and dedication. Each of you brings unique strengths to our team, and together, we can achieve great things. Let\\u2019s set our sights on submitting the proposal by [new deadline date].\\r\\n\\r\\nIf youre facing any hurdles or need additional support, I\\u2019d be happy to set up a meeting or office hours to help you work through any challenges. Please feel free to reach out if you\\u2019d like to schedule a time to discuss your ideas and get feedback.\\r\\n\\r\\nLet\\u2019s rally together, brainstorm, and conquer this task with the excellence I know you\\u2019re capable of. Your efforts are vital to our collective success and will open doors for exciting opportunities ahead.\\r\\n\\r\\nKeep pushing forward, and let\\u2019s make this proposal a testament to your incredible potential. I\\u2019m excited to see what we can accomplish together!\\r\\n\\r\\nWarm regards,\\r\\n[Your\\u00a0Name]\",\"third-essay\":\"\",\"hours_commitment\":\"\",\"time_blocks\":\"\",\"hear_about\":\"\"}', '[]', '2025-06-29 17:00:05'),
('SYSJ0179', '{\"full-name\":\"Mariam Elsounbaty\",\"email-address\":\"mariamahmedelsounbatyy@gmail.com\",\"contact-number\":\"+201202042664\",\"country\":\"Egypt\",\"gender\":\"female\",\"birth-date\":\"2008-03-27\",\"institution\":\"Dakahlia STEM School\",\"grade-year\":\"11\",\"gpa\":\"3.86\",\"interest\":[\"Chemistry,Engineering (not Aerospace Engineering),Environmental Science,Physics & Astrophysics\"],\"interest_ratings\":{\"Chemistry\":\"9\",\"Engineering (not Aerospace Engineering)\":\"8\",\"Environmental Science\":\"10\",\"Physics & Astrophysics\":\"7\"},\"grade-previous\":\"\",\"first-essay\":\"I have always been passionate about how can we integrate chemistry and engineering to \",\"second-essay\":\"\",\"third-essay\":\"\",\"hours_commitment\":\"\",\"time_blocks\":\"\",\"hear_about\":\"\"}', '[]', '2025-06-30 01:42:29'),
