('SYSJ0305', '{\"full-name\":\"\",\"email-address\":\"\",\"contact-number\":\"\",\"country\":\"\",\"birth-date\":\"\",\"institution\":\"\",\"grade-year\":\"\",\"gpa\":\"\",\"interest\":[\"\"],\"grade-previous\":\"\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours_commitment\":\"\",\"time_blocks\":\"\",\"hear_about\":\"\"}', '[]', '2025-07-01 14:26:28'),
('SYSJ0306', '{\"full-name\":\"Nurhan Ayman fawaz\",\"email-address\":\"nurhanaymanfawaz@gmail.com\",\"contact-number\":\"1557568704\",\"country\":\"Egypt \",\"gender\":\"female\",\"birth-date\":\"2009-10-28\",\"institution\":\"\",\"grade-year\":\"Grade 10\",\"gpa\":\"4\",\"interest\":[\"Business, Entrepreneurship, & Strategy,Computer Science,Robotics\"],\"interest_ratings\":{\"Business, Entrepreneurship, & Strategy\":\"9\",\"Computer Science\":\"3\",\"Robotics\":\"6\"},\"grade-previous\":\"\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours_commitment\":\"\",\"time_blocks\":\"\",\"hear_about\":\"\"}', '[]', '2025-07-01 15:02:08'),
('SYSJ0307', '{\"full-name\":\"Rawda almaghraby\",\"email-address\":\"rawdaalmagraby@gmail.com\",\"contact-number\":\"01024721023\",\"country\":\"Egypt\",\"gender\":\"female\",\"birth-date\":\"2009-06-18\",\"institution\":\"Red Sea STEM School\",\"grade-year\":\"G11\",\"gpa\":\"3.6\",\"interest\":[\"Aerospace Engineering,Physics & Astrophysics\"],\"interest_ratings\":{\"Aerospace Engineering\":\"5\",\"Physics & Astrophysics\":\"5\"},\"grade-previous\":\"\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours_commitment\":\"\",\"time_blocks\":\"\",\"hear_about\":\"\"}', '[]', '2025-07-01 17:39:15'),
('SYSJ0308', '{\"full-name\":\"Omar Ahmed\",\"email-address\":\"omar.1324014@stemdakahlia.moe.edu.eg\",\"contact-number\":\"01559419445\",\"country\":\"Egypt\",\"birth-date\":\"2008-08-30\",\"institution\":\"STEM Dakahlia\",\"grade-year\":\"11\",\"gpa\":\"\",\"interest\":[\"Biology,Education,Environmental Science,Linguistics,Mathematics,Medicine & Public Health,Neuroscience & Neurobiology,Physics & Astrophysics,Psychology,Robotics\"],\"interest_ratings\":{\"Biology\":\"9\",\"Education\":\"8\",\"Environmental Science\":\"6\",\"Linguistics\":\"7\",\"Mathematics\":\"9\",\"Medicine & Public Health\":\"7\",\"Neuroscience & Neurobiology\":\"6\",\"Physics & Astrophysics\":\"8\",\"Psychology\":\"5\",\"Robotics\":\"6\"},\"grade-previous\":\"\",\"first-essay\":\"Mentorship in science means more than just knowing facts, it\\u2019s about helping others understand difficult ideas and supporting them when they feel stuck. As a STEM student, I\\u2019ve spent a lot of time learning about science and also explaining it to others, which has helped me become better at both.\\r\\n\\r\\nMy research experience includes working on a project to make clean energy using a Bio-Direct Methanol Fuel Cell. I had to understand how tiny bacteria can turn methane into methanol, and how that can be used in fuel cells. It wasn\\u2019t easy at first, but I kept asking questions, researching, and finding simple ways to explain it. Later, I shared what I learned with others who were interested, and I saw how my explanations helped them get excited about science too.\\r\\n\\r\\nMy goal as a mentor is to make science feel possible for everyone. I want to guide junior researchers step by step, help them ask better questions, and show them how to find answers even if the answers aren\\u2019t clear at first. YSJ\\u2019s focus on student research is something I really admire. It gives young students the chance to do real science and not just read about it.\\r\\n\\r\\nOne time, a younger student was struggling to understand how energy flows in a fuel cell. I used a simple example, comparing it to how water flows in a dam to spin turbines and make electricity. That helped him understand, and he got more interested in the topic. Moments like that are why I love mentoring.\\r\\n\\r\\nYSJ would give me the chance to help more students grow in science and discover what they\\u2019re capable of. I\\u2019m excited to be part of that process..\\r\\n\\r\\n\",\"second-essay\":\"ey Team 123 \\ud83d\\udc4b,\\r\\n\\r\\nI noticed that the Research Idea Proposal deadline has passed, and we haven\\u2019t received your submission yet. I understand that things can get busy or overwhelming, research isn\\u2019t always a straight path, but this is a crucial step in moving your project forward.\\r\\n\\r\\nLet\\u2019s treat this as a push rather than a pause. I believe in your team and the ideas you\\u2019re capable of exploring. If something is blocking your progress, confusion about the topic, trouble narrowing down ideas, or anything else, please reach out. I\\u2019m here to help.\\r\\n\\r\\nThat said, let\\u2019s aim to get your proposal finalized and submitted within the next 48 hours. If you need a quick check-in call or feedback on a draft, just ping me and we\\u2019ll make it happen.\",\"third-essay\":\"\",\"hours_commitment\":\"\",\"time_blocks\":\"\",\"hear_about\":\"\"}', '[]', '2025-07-01 17:56:35'),
('SYSJ0309', '{\"full-name\":\"\",\"email-address\":\"\",\"contact-number\":\"\",\"country\":\"\",\"birth-date\":\"\",\"institution\":\"\",\"grade-year\":\"\",\"gpa\":\"\",\"interest\":[\"\"],\"grade-previous\":\"\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours_commitment\":\"\",\"time_blocks\":\"\",\"hear_about\":\"\"}', '[]', '2025-07-01 18:01:46');
INSERT INTO `application_drafts` (`user_id`, `data`, `files`, `updated_at`) VALUES
('SYSJ0310', '{\"full-name\":\"Maryam mostafa abdo ahmed \",\"email-address\":\"maryamostafa.abdo@gmail.com\",\"contact-number\":\"+201065147036\",\"country\":\"Egypt \",\"birth-date\":\"2006-09-18\",\"institution\":\"Helwan university \",\"grade-year\":\"First year\",\"gpa\":\"2.9\",\"interest\":[\"Biology\",\"Chemistry\",\"Medicine & Public Health\"],\"grade-previous\":\"Biology 90\\/100 chemistry 78\\/100 public health 100\\/100\",\"first-essay\":\"As a Therapeutic Nutrition student with a strong interest in STEM outreach, I\\u2019ve actively pursued opportunities to deepen my understanding of science and share that knowledge. Through coursework in biology, chemistry, and human physiology, I\\u2019ve developed a foundational knowledge that I often simplify and explain to classmates, especially those who find scientific concepts intimidating.\\r\\n\\r\\nIn high school, I led study groups during our biology and chemistry revisions, using analogies, color-coded diagrams, and mini-competitions to keep sessions engaging. I wasn\\u2019t just helping them memorize\\u2014I focused on building their confidence and critical thinking, which I believe is the essence of mentorship.\\r\\nOne moment I\\u2019m particularly proud of was helping a fellow student who struggled with understanding protein synthesis. She felt discouraged and \\u201cnot cut out\\u201d for science. I broke down the concept using a story format\\u2014turning DNA into a character giving orders, the ribosome into a translator, and amino acids into puzzle pieces. She not only understood it afterward but started asking deeper questions, curious about how diet affects gene expression.\\r\\n\\r\\nMore recently, I co-led a short peer session on malnutrition and micronutrients for younger students during a university club event. Some found the topic overwhelming, so I used real-life scenarios and simple infographics. Their feedback showed they left the session feeling more interested in how science connects to real life.\",\"second-essay\":\"Hey Team 123! \\ud83c\\udf1f\\r\\n\\r\\nI hope you\\u2019re all doing well. I noticed that your Research Idea Proposal hasn\\u2019t been submitted yet, and the deadline has now passed. I understand things can get overwhelming\\u2014we\\u2019ve all been there\\u2014but timely submissions are crucial for keeping the whole project on track. \\r\\n\\r\\nPlease take this as a gentle but urgent reminder: we need your proposal finalized and submitted within the next 24 hours. If you\\u2019re facing any blockers\\u2014whether it\\u2019s uncertainty about your topic, team coordination, or anything else\\u2014don\\u2019t hesitate to reach out. I\\u2019m here to help guide you through it.\\r\\n\\r\\nLet\\u2019s wrap this up and get back on track. I believe in your team and the potential your project has. Let\\u2019s make it happen! \\ud83d\\udcaa\\ud83c\\udffb\\ud83e\\udd29\\r\\n\\r\\n\\u2014 [Your Name],\\r\\nYSJ Senior Researcher\\r\\n\",\"third-essay\":\"As an undergraduate student in Therapeutic Nutrition at Helwan University, my research journey is still growing, but I\\u2019ve already begun to engage deeply with scientific questions that lie at the intersection of human health, public education, and nutrition science. My academic coursework has given me a strong foundation in biology, biochemistry, and public health, which I\\u2019ve expanded through self-led learning and academic competitions.\\r\\n\\r\\nThough I haven\\u2019t yet published formal research papers or patents, I\\u2019ve been part of student-led initiatives aimed at simplifying complex nutrition concepts for underserved communities. One of these projects involved preparing awareness materials on iron deficiency anemia, where I researched the biochemistry behind it, designed infographics, and presented them at a university event for first-year students. I\\u2019ve also worked in small peer teams to analyze food composition data using national food tables and convert it into usable dietary plans\\u2014a process that helped sharpen both my analytical and data interpretation skills.\\r\\n\\r\\nAdditionally, I actively contribute to science-focused clubs and online platforms, and I\\u2019m working toward submitting my first abstract for a local youth science forum. My interests lie in evidence-based approaches to disease prevention and using science communication to promote healthier communities.\\r\\n\\r\\nI\\u2019m excited to take on more structured research opportunities, develop my skills in scientific writing and peer collaboration, and contribute to the YSJ network of young researchers.\\r\\n\",\"hours_commitment\":\"\",\"time_blocks\":\"\",\"hear_about\":\"\",\"gender\":\"female\",\"interest_ratings\":{\"Biology\":\"9\",\"Chemistry\":\"7\",\"Medicine & Public Health\":\"10\"}}', '{\"research_files\":[],\"commented_files\":[{\"name\":\"YSJ_Final_Polished_Research_Paper.docx\",\"path\":\"uploads\\/SYSJ0310\\/drafts\\/686977866b662_YSJ_Final_Polished_Research_Paper.docx\",\"size\":39462,\"type\":\"application\\/vnd.openxmlformats-officedocument.wordprocessingml.document\"}],\"additional_files\":[]}', '2025-07-05 19:05:42'),
('SYSJ0311', '{\"full-name\":\"Hanan Mohamed \",\"email-address\":\"hananmohamed6736@gmail.com\",\"contact-number\":\"+201118882692\",\"country\":\"Egypt\",\"birth-date\":\"2009-04-26\",\"institution\":\"Omar ibn elkhtab language school (Egypt government)\",\"grade-year\":\"Grade 10 (2025-2026)\",\"gpa\":\"93.9%\",\"interest\":[\"Arts\",\"Chemistry\",\"Neuroscience & Neurobiology\",\"Psychology\"],\"grade-previous\":\"N\\/A\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours_commitment\":\"\",\"time_blocks\":\"\",\"hear_about\":\"\",\"gender\":\"female\",\"interest_ratings\":{\"Arts\":\"9\",\"Chemistry\":\"5\",\"Neuroscience & Neurobiology\":\"0\",\"Psychology\":\"5\"}}', '{\"research_files\":[],\"commented_files\":[],\"additional_files\":[]}', '2025-07-05 18:59:20'),
