('SYSJ0327', '{\"full-name\":\"ASMAA RADY \",\"email-address\":\"sheashaaasmaa29@gmail.com\",\"contact-number\":\"01002114506\",\"country\":\"Kafr El Sheikh \",\"gender\":\"female\",\"birth-date\":\"2009-02-26\",\"institution\":\"Barnabal Secondary School \",\"grade-year\":\"Second secondary grade \",\"gpa\":\"84%\",\"interest\":[\"Mathematics,Medicine & Public Health\"],\"interest_ratings\":{\"Mathematics\":\"5\",\"Medicine & Public Health\":\"5\"},\"grade-previous\":\"nothing \",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"I dont have any of these things.  \",\"hours_commitment\":\"21\",\"time_blocks\":\"The start of june\",\"hear_about\":\"WhatsApp \"}', '[]', '2025-07-02 12:10:55'),
