('SYSJ0330', '{\"full-name\":\"Lan Sun\",\"email-address\":\"daisylansun@outlook.com\",\"contact-number\":\"+86 15810169537\",\"country\":\"China\",\"gender\":\"female\",\"birth-date\":\"2010-01-13\",\"institution\":\"Keystone Academy\",\"grade-year\":\"Class of 2028\",\"gpa\":\"I can send my transcript, although there is no GPA calculated.\",\"interest\":[\"Education,Environmental Science,History & Civilizations,Medicine & Public Health,Sociology & Anthropology\"],\"interest_ratings\":{\"Education\":\"8\",\"Environmental Science\":\"8\",\"History & Civilizations\":\"8\",\"Medicine & Public Health\":\"7\",\"Sociology & Anthropology\":\"7\"},\"grade-previous\":\"We do not have these specific courses. But I can send my transcript.\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours_commitment\":\"\",\"time_blocks\":\"\",\"hear_about\":\"\"}', '[]', '2025-07-02 09:52:46'),
