('SYSJ0352', '{\"full-name\":\"Ahmed Saif Eldeen\",\"email-address\":\"ahmedsaifeldeen1314@gmail.com\",\"contact-number\":\"01091310012\",\"country\":\"Egypt\",\"gender\":\"male\",\"birth-date\":\"2008-08-13\",\"institution\":\"STEM\",\"grade-year\":\"adsaf\",\"gpa\":\"8\",\"interest\":[\"Arts\"],\"interest_ratings\":{\"Arts\":\"5\"},\"grade-previous\":\"5\",\"first-essay\":\"Mentorship in scientific research requires a comprehensive understanding of the concepts and the ability to motivate and direct students as they go through their difficulties. Analyze this quote and discuss how your experiences and knowledge in scientific research have prepared you enough to fit yourself into YSJs high standards.\\r\\n\\r\\nIn your response, state your academic and mentoring goals, explaining how some aspects of YSJ would help you direct young researchers toward their potential.\\r\\n\\r\\nFurthermore, give examples of situations where you have helped learners wade through complex problems to aid their growth and excitement for science. Mentorship in scientific research requires a comprehensive understanding of the concepts and the ability to motivate and direct students as they go through their difficulties. Analyze this quote and discuss how your experiences and knowledge in scientific research have prepared you enough to fit yourself into YSJs high standards.\\r\\n\\r\\nIn your response, state your academic and mentoring goals, explaining how some aspects of YSJ would help you direct young researchers toward their potential.\\r\\n\\r\\nFurthermore, give examples of situations where you have helped learners wade through complex problems to aid their growth and excitement for science. Mentorship in scientific research requires a comprehensive understanding of the concepts and the ability to motivate and direct students as they go through their difficulties. Analyze this quote and discuss how your experiences and knowledge in scientific research have prepared you enough to fit yourself into YSJs high standards.\\r\\n\\r\\nIn your response, state your academic and mentoring goals, explaining how some aspects of YSJ would help you direct young researchers toward their potential.\\r\\n\\r\\nFurthermore, give examples of situations where you have helped learners wade through complex problems to aid their growth and excitement for science. \",\"second-essay\":\"Mentorship in scientific research requires a comprehensive understanding of the concepts and the ability to motivate and direct students as they go through their difficulties. Analyze this quote and discuss how your experiences and knowledge in scientific research have prepared you enough to fit yourself into YSJs high standards.\\r\\n\\r\\nIn your response, state your academic and mentoring goals, explaining how some aspects of YSJ would help you direct young researchers toward their potential.\\r\\n\\r\\nFurthermore, give examples of situations where you have helped learners wade through complex problems to aid their growth and excitement for science. Mentorship in scientific research requires a comprehensive understanding of the concepts and the ability to motivate and direct students as they go through their difficulties. Analyze this quote and discuss how your experiences and knowledge in scientific research have prepared you enough to fit yourself into YSJs high standards.\\r\\n\\r\\nIn your response, state your academic and mentoring goals, explaining how some aspects of YSJ would help you direct young researchers toward their potential.\\r\\n\\r\\nFurthermore, give examples of situations where you have helped learners wade through complex problems to aid their growth and excitement for science. Mentorship in scientific research requires a comprehensive understanding of the concepts and the ability to motivate and direct students as they go through their difficulties. Analyze this quote and discuss how your experiences and knowledge in scientific research have prepared you enough to fit yourself into YSJs high standards.\\r\\n\\r\\nIn your response, state your academic and mentoring goals, explaining how some aspects of YSJ would help you direct young researchers toward their potential.\\r\\n\\r\\nFurthermore, give examples of situations where you have helped learners wade through complex problems to aid their growth and excitement for science. \",\"third-essay\":\"Mentorship in scientific research requires a comprehensive understanding of the concepts and the ability to motivate and direct students as they go through their difficulties. Analyze this quote and discuss how your experiences and knowledge in scientific research have prepared you enough to fit yourself into YSJs high standards.\\r\\n\\r\\nIn your response, state your academic and mentoring goals, explaining how some aspects of YSJ would help you direct young researchers toward their potential.\\r\\n\\r\\nFurthermore, give examples of situations where you have helped learners wade through complex problems to aid their growth and excitement for science. Mentorship in scientific research requires a comprehensive understanding of the concepts and the ability to motivate and direct students as they go through their difficulties. Analyze this quote and discuss how your experiences and knowledge in scientific research have prepared you enough to fit yourself into YSJs high standards.\\r\\n\\r\\nIn your response, state your academic and mentoring goals, explaining how some aspects of YSJ would help you direct young researchers toward their potential.\\r\\n\\r\\nFurthermore, give examples of situations where you have helped learners wade through complex problems to aid their growth and excitement for science. Mentorship in scientific research requires a comprehensive understanding of the concepts and the ability to motivate and direct students as they go through their difficulties. Analyze this quote and discuss how your experiences and knowledge in scientific research have prepared you enough to fit yourself into YSJs high standards.\\r\\n\\r\\nIn your response, state your academic and mentoring goals, explaining how some aspects of YSJ would help you direct young researchers toward their potential.\\r\\n\\r\\nFurthermore, give examples of situations where you have helped learners wade through complex problems to aid their growth and excitement for science. \",\"hours_commitment\":\"\",\"time_blocks\":\"\",\"hear_about\":\"\"}', '{\"research_files\":[{\"name\":\"Cancer Treatment Treatment of Leukemia using HIV as a Viral Vector.pdf\",\"path\":\"uploads\\/SYSJ0352\\/drafts\\/Cancer_Treatment_Treatment_of_Leukemia_using_HIV_as_a_Viral_Vector.pdf\",\"size\":396403,\"type\":\"application\\/pdf\"}]}', '2025-07-03 05:34:13'),
('SYSJ0353', '{\"full-name\":\"\",\"email-address\":\"\",\"contact-number\":\"\",\"country\":\"\",\"birth-date\":\"\",\"institution\":\"\",\"grade-year\":\"\",\"gpa\":\"\",\"interest\":[\"\"],\"grade-previous\":\"\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours_commitment\":\"\",\"time_blocks\":\"\",\"hear_about\":\"\"}', '[]', '2025-07-03 07:37:02'),
('SYSJ0354', '{\"full-name\":\"Pradipti Nath\",\"email-address\":\"pradiptienvisions1101@gmail.com\",\"contact-number\":\"9833896847\",\"country\":\"India\",\"gender\":\"female\",\"birth-date\":\"2009-01-11\",\"institution\":\"Oberoi international school\",\"grade-year\":\"11\",\"gpa\":\"3.86\",\"interest\":[\"Biology,Economics,Environmental Science,Sociology & Anthropology\"],\"interest_ratings\":{\"Biology\":\"9\",\"Economics\":\"9\",\"Environmental Science\":\"10\",\"Sociology & Anthropology\":\"7\"},\"grade-previous\":\"Biology IGCSE Level - A* (96%), Economics IGCSE (87%) and IB Diploma Higher Level, Business Strategy (Self Taught via Coursera, Springpod), Environmental Science (IB Diploma at a Higher Level). The rest are interests I read a lot about on the internet, write research papers on etc.    \",\"first-essay\":\"To me, mentorship in scientific research isn\\u2019t just about answering questions it\\u2019s about equipping learners to ask the right ones. It requires patience, clarity, and the humility to guide rather than instruct. Through my own academic journey, I\\u2019ve learned that the most meaningful mentorship happens not in delivering solutions, but in walking beside others as they discover them for themselves. It\\u2019s with this mindset that I believe I align with the ethos of the Young Scientists Journal (YSJ). Over the past year, I\\u2019ve led a club of 50+ students where we explored Artificial Intelligence and its real-world applications. These weren\\u2019t just lectures they were labs of curiosity, where we demystified neural networks and debated the ethics of facial recognition. I vividly recall one student struggling with machine learning algorithms. Instead of simplifying the concept for her, I challenged her to reverse-engineer a model using real data. The moment she cracked it and presented her findings to the club was a defining one for both of us. \\r\\nOutside the screen-lit classrooms, I initiated a study group for IGCSE Biology students, held weekly at a nearby garden. What began as casual tutoring evolved into a space of open dialogue. We\\u2019d relate mitosis to leaf patterns around us, turning the natural world into a live textbook! One student, previously demotivated by rigid academic structures and began to show up early bringing questions! Perhaps the most formative experience was leading a team of six students on a collaborative research paper titled Citizen Science: How People Use Digital Tools to Share Local Data. As the team lead, I steered us through academic writing, methodological frameworks, and late-night debates over ethical data collection. It wasn\\u2019t just distributing tasks but about learning how to hold space for uncertainty, disagreement, and eventual insight. \\r\\nMy academic and mentoring goals centre on making research feel personal, purposeful, and empowering. YSJ\\u2019S commitment to nurturing young researchers mirrors what I value most  mentorship that sparks ownership and I hope to do the same at YSJ too. \\r\\n\",\"second-essay\":\"Hey Team123!\\r\\nI noticed the Research Idea Proposal deadline has passed, and we haven\\u2019t received your submission yet. I completely understand that things can get hectic, but it\\u2019s really important we stay on track to ensure the entire research cycle runs smoothly.\\r\\nIf youre facing any challenges be it finalizing your idea, team coordination, or anything else, please don\\u2019t hesitate to reach out. I\\u2019d be happy to help you troubleshoot or guide you through the next steps!  That said, I\\u2019ll need your finalized proposal within the next 48 hours so we can move forward without delays. Let\\u2019s push through this milestone, you\\u2019ve got this!\\r\\n\",\"third-essay\":\"My research background spans both independent work and collaborative projects, rooted in social impact and real-world relevance.\\r\\nThrough the Young Researchers for Social Impact (YRSI) program by YLAC, I was ed as one of 90 students from over 19,000 applicants. Our cohort explored the theme of digital citizen science, specifically how individuals and local communities use digital tools to collect, share, and analyze local data for environmental and social change. I co-authored a research paper with six peers, where I served as the team lead. We investigated case studies, digital platforms, and ethical concerns around data collection. I guided the group through task delegation, research design, and synthesis of findings into a well-structured final paper. This experience helped me grow as a collaborative researcher and gave me a deeper appreciation for grassroots participation in scientific inquiry.\\r\\nSeparately, I worked on a Global Perspectives project at school with three peers on Gender Inequality in India. We explored the issue through educational access, wage disparity, and cultural norms. Our research combined interviews, survey design, and secondary data, and culminated in a multimedia presentation and report. I took the lead on data interpretation, using visual analysis tools to highlight gaps in opportunity for women across urban and rural India. This project taught me the value of contextualizing data within lived experiences and emphasized the role of narrative in research communication.\\r\\nBoth experiences have shaped my approach to research as rigorous, team-oriented, and impact-focused. Whether leading or collaborating, I aim to make research accessible and meaningful beyond the academic space too : ) \\r\\n\",\"hours_commitment\":\"14\",\"time_blocks\":\"Having my fall vacations right now, so I am free :) School starts in September!\",\"hear_about\":\"Reddit, Google Search\"}', '{\"research_files\":[{\"name\":\"Project Plan_ Citizen Science Made Simple_ How People Use Digital Tools to Share Local Data.pdf\",\"path\":\"uploads\\/SYSJ0354\\/drafts\\/Project_Plan__Citizen_Science_Made_Simple__How_People_Use_Digital_Tools_to_Share_Local_Data.pdf\",\"size\":378327,\"type\":\"application\\/pdf\"},{\"name\":\"Gender Inequality Project Grp 5.pdf\",\"path\":\"uploads\\/SYSJ0354\\/drafts\\/Gender_Inequality_Project_Grp_5.pdf\",\"size\":316777,\"type\":\"application\\/pdf\"}],\"commented_files\":[],\"additional_files\":[]}', '2025-07-03 12:10:23'),
('SYSJ0355', '{\"full-name\":\"Dana Sharaf \",\"email-address\":\"danasharaf099123@gmail.com\",\"contact-number\":\"0996756636\",\"country\":\"Syrian\",\"gender\":\"female\",\"birth-date\":\"2009-05-14\",\"institution\":\"toppers high school in syria\",\"grade-year\":\"11  \",\"gpa\":\"4\",\"interest\":[\"Biology,Chemistry,Medicine & Public Health,Psychology\"],\"interest_ratings\":{\"Biology\":\"9\",\"Chemistry\":\"7\",\"Medicine & Public Health\":\"8\",\"Psychology\":\"8\"},\"grade-previous\":\"biology 97 , chemistry 96, I dont have public health class and psychology class \",\"first-essay\":\"I am applying as a student participant, not as a mentor but I have participated in an astronomy competition and did researches with my team so I have a well-rounded knowledge but i want to dive deep with you\",\"second-essay\":\"\",\"third-essay\":\"I have participated in an astronomy competition and did researches with my team so i have a well-rounded knowledge but i want to dive deep with you\",\"hours_commitment\":\"7\",\"time_blocks\":\"From July 25 to  September  1\",\"hear_about\":\"From my friends \"}', '{\"research_files\":[{\"name\":\"PEKK.docx\",\"path\":\"uploads\\/SYSJ0355\\/drafts\\/PEKK.docx\",\"size\":205729,\"type\":\"application\\/vnd.openxmlformats-officedocument.wordprocessingml.document\"}],\"additional_files\":[{\"name\":\"IMG_\\u0662\\u0660\\u0662\\u0665\\u0660\\u0667\\u0660\\u0663_\\u0661\\u0663\\u0660\\u0669\\u0662\\u0665.jpg\",\"path\":\"uploads\\/SYSJ0355\\/drafts\\/IMG______________________________.jpg\",\"size\":22524,\"type\":\"image\\/jpeg\"}]}', '2025-07-03 10:22:39'),
