('SYSJ0426', '{\"full_name\":\"Ahmed Saif Eldeen\",\"email-address\":\"holadaf@gmail.com\",\"contact-number\":\"+201091310012\",\"country\":\"Egypt\",\"birth-date\":\"2008-08-13\",\"institution\":\"STEM\",\"grade-year\":\"adsaf\",\"gpa\":\"8\",\"interest\":\"Arts\",\"grade-previous\":\"5\",\"first-essay\":\"What extracurricular activities and achievements have you pursued in your area of academic interest?\\r\\nThese may range from as simple as winning a school competition to more intensive experiences such as Olympiads or internships. *What extracurricular activities and achievements have you pursued in your area of academic interest?\\r\\nThese may range from as simple as winning a school competition to more intensive experiences such as Olympiads or internships. *What extracurricular activities and achievements have you pursued in your area of academic interest?\\r\\nThese may range from as simple as winning a school competition to more intensive experiences such as Olympiads or internships. *\",\"second-essay\":\"\",\"third-essay\":\"\",\"fourth-essay\":\"\",\"hours_commitment\":\"\",\"time_blocks\":\"\",\"hear_about\":\"\",\"additional-essay\":\"\",\"interest_ratings\":{\"Arts\":\"5\"}}', NULL, '2025-08-07 01:11:54'),
('SYSJ044', '{\"full-name\":\"Full Name (First and Second)\",\"email-address\":\"email@email.com\",\"contact-number\":\"01111605702\",\"country\":\"Country of Nationality\",\"gender\":\"male\",\"birth-date\":\"2025-06-12\",\"institution\":\"Institution \",\"grade-year\":\"Grade Year\",\"gpa\":\"GPA\",\"interest\":\"Fields of Interest\",\"grade-previous\":\"Grade of each respective field in previous academic years (if applicable)\",\"first-essay\":\"Mentorship in scientific research requires a comprehensive understanding of the concepts and the ability to motivate and direct students as they go through their difficulties. Analyze this quote and discuss how your experiences and knowledge in scientific research have prepared you enough to fit yourself into YSJ\'s high standards.\\r\\n\\r\\nIn your response, state your academic and mentoring goals, explaining how some aspects of YSJ would help you direct young researchers toward their potential.\\r\\n\\r\\nFurthermore, give examples of situations where you have helped learners wade through complex problems to aid their growth and excitement for science.\\r\\nMentorship in scientific research requires a comprehensive understanding of the concepts and the ability to motivate and direct students as they go through their difficulties. Analyze this quote and discuss how your experiences and knowledge in scientific research have prepared you enough to fit yourself into YSJ\'s high standards.\\r\\n\\r\\nIn your response, state your academic and mentoring goals, explaining how some aspects of YSJ would help you direct young researchers toward their potential.\\r\\n\\r\\nFurthermore, give examples of situations where you have helped learners wade through complex problems to aid their growth and excitement for science.\\r\\nMentorship in scientific research requires a comprehensive understanding of the concepts and the ability to motivate and direct students as they go through their difficulties. Analyze this quote and discuss how your experiences and knowledge in scientific research have prepared you enough to fit yourself into YSJ\'s high standards.\\r\\n\\r\\nIn your response, state your academic and mentoring goals, explaining how some aspects of YSJ would help you direct young researchers toward their potential.\\r\\n\\r\\nFurthermore, give examples of situations where you have helped learners wade through complex problems to aid their growth and excitement for science.\",\"second-essay\":\"Consider you\'re a YSJ senior researcher. One of your teams, perhaps team 123, has failed to stick to the Research idea proposal deadline. Write a message you\'d send them via discord to push them to finish their task\",\"third-essay\":\"Please describe your research background, including your areas of expertise, the research projects (e.g., papers, projects, and\\/or patents) you have been involved in, and\\/or any publications or presentations resulting from your research. (Word Limit: 150-300 words)\\r\\nPlease describe your research background, including your areas of expertise, the research projects (e.g., papers, projects, and\\/or patents) you have been involved in, and\\/or any publications or presentations resulting from your research. (Word Limit: 150-300 words)\\r\\nPlease describe your research background, including your areas of expertise, the research projects (e.g., papers, projects, and\\/or patents) you have been involved in, and\\/or any publications or presentations resulting from your research. (Word Limit: 150-300 words)\\r\\nPlease describe your research background, including your areas of expertise, the research projects (e.g., papers, projects, and\\/or patents) you have been involved in, and\\/or any publications or presentations resulting from your research. (Word Limit: 150-300 words)\\r\\nPlease describe your research background, including your areas of expertise, the research projects (e.g., papers, projects, and\\/or patents) you have been involved in, and\\/or any publications or presentations resulting from your research. (Word Limit: 150-300 words)\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '{\"research_files\":[{\"name\":\"EBO Website.docx\",\"path\":\"uploads\\/SYSJ044\\/drafts\\/EBO_Website.docx\",\"size\":22184,\"type\":\"application\\/vnd.openxmlformats-officedocument.wordprocessingml.document\"}],\"commented_files\":[{\"name\":\"EBO Website (English Version).docx\",\"path\":\"uploads\\/SYSJ044\\/drafts\\/EBO_Website__English_Version_.docx\",\"size\":21108,\"type\":\"application\\/vnd.openxmlformats-officedocument.wordprocessingml.document\"}]}', '2025-06-12 17:05:43'),
('SYSJ049', '{\"full-name\":\"Full Name (First and Second)\",\"email-address\":\"email@email.com\",\"contact-number\":\"01111605702\",\"country\":\"Country of Nationality\",\"gender\":\"male\",\"birth-date\":\"2025-06-20\",\"institution\":\"Institution \",\"grade-year\":\"2025\",\"gpa\":\"GPA \",\"interest\":\"Fields of Interest\",\"grade-previous\":\"Grade of each respective field in previous academic years (if applicable)\",\"first-essay\":\"Mentorship in scientific research requires a comprehensive understanding of the concepts and the ability to motivate and direct students as they go through their difficulties. Analyze this quote and discuss how your experiences and knowledge in scientific research have prepared you enough to fit yourself into YSJs high standards.\\r\\n\\r\\nIn your response, state your academic and mentoring goals, explaining how some aspects of YSJ would help you direct young researchers toward their potential.\\r\\n\\r\\nFurthermore, give examples of situations where you have helped learners wade through complex problems to aid their growth and excitement for science. \\r\\nMentorship in scientific research requires a comprehensive understanding of the concepts and the ability to motivate and direct students as they go through their difficulties. Analyze this quote and discuss how your experiences and knowledge in scientific research have prepared you enough to fit yourself into YSJs high standards.\\r\\n\\r\\nIn your response, state your academic and mentoring goals, explaining how some aspects of YSJ would help you direct young researchers toward their potential.\\r\\n\\r\\nFurthermore, give examples of situations where you have helped learners wade through complex problems to aid their growth and excitement for science. \\r\\nMentorship in scientific research requires a comprehensive understanding of the concepts and the ability to motivate and direct students as they go through their difficulties. Analyze this quote and discuss how your 