('SYSJ053', '{\"full-name\":\"Mariam Amir \",\"email-address\":\"mariamamirhanna2@gmail.com\",\"contact-number\":\"01204719255\",\"country\":\"Egypt\",\"gender\":\"female\",\"birth-date\":\"2007-04-26\",\"institution\":\"The Model School \",\"grade-year\":\"12\",\"gpa\":\"93%\",\"interest\":[\"Biology,Environmental Science,Medicine & Public Health,Neuroscience & Neurobiology\"],\"interest_ratings\":{\"Biology\":\"10\",\"Environmental Science\":\"10\",\"Medicine & Public Health\":\"9\",\"Neuroscience & Neurobiology\":\"9\"},\"grade-previous\":\"A+\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '[]', '2025-06-18 13:40:05'),
