INSERT INTO `application_drafts` (`user_id`, `data`, `files`, `updated_at`) VALUES
('SYSJ056', '{\"full-name\":\"Yaseen Saad-Eldin Mohamed-Sabry Mohamed-Abdelal\",\"email-address\":\"yaseen.saad.frontend@gmail.com\",\"contact-number\":\"+201033553865\",\"country\":\"Egypt\",\"birth-date\":\"2008-03-11\",\"institution\":\"STEM High School for Boys - 6th of October\",\"grade-year\":\"Rising Senior\",\"gpa\":\"4.0\",\"interest\":[\"Chemistry\",\"Computer Science\",\"Physics & Astrophysics\"],\"grade-previous\":\"Grade 10: Physics: A+ S1,S2 - Computer Science: A S1,S2 - Chemistry: B+ S1, A S2.     Grade 11: Physics: A S1, S2 - Computer Science: A S1, S2 - Chemistry: A+ S1, A S2.\",\"first-essay\":\"Becoming a strong mentor in scientific research means you not only understand the concepts inside and out, but you can also inspire and guide students when they hit a wall. My background in theoretical physics and computational science, combined with my mentoring experiences, has really prepared me to meet the high standards at YSJ.\\r\\n\\r\\nMy main goal academically is to connect science with real-world applications through computation. As a mentor at YSJ, I want to help  a new generation of researchers who are not just technically skilled, but also truly passionate. I want to help turn their curiosity into meaningful research.\\r\\n\\r\\nWhen I was a Capstone Assistant, I got to help students navigate some pretty complex issues. One team was trying to choose the suitable truss for their bridge, and their initial models just werent cutting it. Instead of just giving them the answer, I pushed them to go back to basics, walking them through the process of refining their models step by step. We broke down the complicated force transfers into smaller, easier-to-understand parts, which helped them figure out where they went wrong. It was tough for them at first, but it led to a really solid and accurate model, and they ended up getting an A+ on their project. For me, it wasnt just about fixing a problem it was about teaching them how to break down something complex and systematically build a solution.\\r\\n\\r\\nAnother time, in the Physics Club, I threw out a bonus computational problem that really stumped a lot of students. It was about finding the optimal posting moment for a viral TikTok video based on 24 hours of cumulative view data. The task involved using polynomial fitting to  a 5th-degree polynomial from the data and then using that polynomial to pinpoint the exact second of peak views per second rate. Many students initially struggled with how to approach a problem. I guided them through understanding the data, and then showed them how to implement polynomial fitting in code. Seeing them light up as they successfully modeled the videos growth and identified that optimal moment was incredibly rewarding it showed them how powerful computational tools can be in unexpected areas.\\r\\nThese experiences, blending my strong theoretical knowledge with practical application and a genuine commitment to mentorship, make me confident that I can make a real contribution to YSJs goal of fostering innovative research.\",\"second-essay\":\"Hello Team 123,\\r\\nRegarding the Research Idea Proposal: this deadline has now passed.\\r\\nMeeting these deadlines is not a matter of formality its of the greatest importance if you are to succeed and for your work to move forward. Timely submissions enable planning for subsequent stages, and keep your projects momentum going. \\r\\nHonestly, Ive seen the consequences of lateness last year, a few junior colleagues, were unfortunately dismissed from the program due to their inability to meet deadlines. This is not meant to scare you, but to illustrate the very real impact these commitments have on your work.\\r\\n\\r\\nProvide me with a status report on your proposal immediately and a clear estimated time of submission. This is not just for single assignments, but for your overall commitment and progress as well.\\r\\nRemember, I am here to assist you in being successful. If you are experiencing any barriers or need a speedy brainstorming session, dont hesitate to reach me at any time. Lets get this done. You can do it.\",\"third-essay\":\"My research background is mostly in theoretical physics and computational science, focusing on applying advanced algorithms to complex scientific problems. My expertise spans computational physics, computational astrophysics, and computational chemistry.\\r\\nA significant aspect of my experience comes from my schools Capstone program, where Ive maintained a streak of A+ grades across all four past semesters. These projects have allowed me to apply theoretical knowledge to practical challenges, such as developing a hydrogen heater, which was a heater that generates electricity and heats up water using only wasted soda cans. Furthermore, as a Capstone Assistant, I guided 5 teams, and their projects collectively earned half of all A+ grades awarded across the entire school.\\r\\nMy involvement as a Junior Researcher at the Youth Science Journal last year focused on computational astrophysics. My project specifically involved proposing a machine learning method to predict star death scenarios, aiming to address a literature gap in dynamic stellar evolution modeling. This work, though still in its data training phase, has significantly deepened my understanding of predictive modeling and large-scale data analysis in scientific contexts.\\r\\nBeyond these projects, Ive actively engaged in applied computational research. As a founder and organizer of the first Computational Science Olympiad in Egypt, Ive designed and implemented platforms that challenge students with complex scientific computing problems.\\r\\nThese experiences, combining rigorous theoretical study with practical computational application and the development of platforms for scientific engagement, have prepared me to contribute to YSJs high standards of innovative research.\",\"hours_commitment\":\"5\",\"time_blocks\":\"SAT Trial Exam, IPhR Competition (I am the Organizer)\",\"hear_about\":\"Junior Last Year\",\"gender\":\"male\",\"interest_ratings\":{\"Chemistry\":\"8\",\"Computer Science\":\"7\",\"Physics & Astrophysics\":\"9\"}}', '{\"research_files\":{\"2\":{\"name\":\"YSJ Research (Repaired).docx\",\"path\":\"uploads\\/SYSJ056\\/drafts\\/686990e9cb3c5_YSJ_Research__Repaired_.docx\",\"size\":166101,\"type\":\"application\\/vnd.openxmlformats-officedocument.wordprocessingml.document\"},\"3\":{\"name\":\"YSJ Research II.docx\",\"path\":\"uploads\\/SYSJ056\\/drafts\\/686990e9cb4d2_YSJ_Research_II.docx\",\"size\":1998440,\"type\":\"application\\/vnd.openxmlformats-officedocument.wordprocessingml.document\"}},\"commented_files\":[{\"name\":\"A Comparative Study of the Perceived Stress Levels and Sources of Stress.pdf\",\"path\":\"uploads\\/SYSJ056\\/drafts\\/6869a1f01873b_A_Comparative_Study_of_the_Perceived_Stress_Levels_and_Sources_of_Stress.pdf\",\"size\":426402,\"type\":\"application\\/pdf\"}],\"additional_files\":{\"3\":{\"name\":\"YSJ Research (Repaired).docx\",\"path\":\"uploads\\/SYSJ056\\/drafts\\/68699a3ecfe29_YSJ_Research__Repaired_.docx\",\"size\":166101,\"type\":\"application\\/vnd.openxmlformats-officedocument.wordprocessingml.document\"}}}', '2025-07-05 22:51:25'),
('SYSJ057', '{\"full-name\":\"Aly Al-Gendy\",\"email-address\":\"aly.algendy.2008@gmail.com\",\"contact-number\":\"01276232538\",\"country\":\"Egypt\",\"gender\":\"male\",\"birth-date\":\"2008-07-01\",\"institution\":\"STEM High School for Boys - 6th of October\",\"grade-year\":\"Grade 12\",\"gpa\":\"3.7\",\"interest\":[\"Architecture,Physics & Astrophysics\"],\"interest_ratings\":{\"Architecture\":\"6\",\"Physics & Astrophysics\":\"10\"},\"grade-previous\":\"N\\/A\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '[]', '2025-06-18 14:03:10'),
('SYSJ058', '{\"full-name\":\"Hamza Elrawy\",\"email-address\":\"hamzaelrawy4@gmail.com\",\"contact-number\":\"01150547379\",\"country\":\"Egypt\",\"birth-date\":\"2008-03-25\",\"institution\":\"STEM High School for Boys - 6th of October\",\"grade-year\":\"11\",\"gpa\":\"3.7\",\"interest\":[\"Engineering (not Aerospace Engineering),Mathematics,Robotics\"],\"interest_ratings\":{\"Engineering (not Aerospace Engineering)\":\"8\",\"Mathematics\":\"6\",\"Robotics\":\"4\"},\"grade-previous\":\"G10: Math:B+, Mechanics:B+.   G11: Math:B+, Mechanics:B+\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '[]', '2025-06-18 14:03:25'),
('SYSJ059', '{\"full-name\":\"Omar Hossam\",\"email-address\":\"omarhossam262009@gmail.com\",\"contact-number\":\"+201104806653\",\"country\":\"Egypt \",\"birth-date\":\"2009-06-02\",\"institution\":\"Om Elabtal experimental secondary language school for boys \",\"grade-year\":\"10 \",\"gpa\":\"85 out of 100 \",\"interest\":[\"Mathematics\"],\"interest_ratings\":{\"Mathematics\":\"5\"},\"grade-previous\":\".\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '[]', '2025-06-18 14:03:50'),
('SYSJ060', '{\"full-name\":\"Ahmed Mahmoud Gamil\",\"email-address\":\"amgamil2007@gmail.com\",\"contact-number\":\"01063745049\",\"country\":\"Egypt\",\"gender\":\"male\",\"birth-date\":\"2007-04-11\",\"institution\":\"Stem october\",\"grade-year\":\"Junior \",\"gpa\":\"3.7\",\"interest\":[\"Biology\",\"Chemistry\"],\"interest_ratings\":{\"Biology\":\"10\",\"Chemistry\":\"8\"},\"grade-previous\":\"B+\",\"first-essay\":\"Since enrolling in STEM, I have always been eager to learn everything possible about the research track, whether it was from seniors, clubs, programs, or even Coursera courses. That got me interested in teaching everything I learned to my juniors to help in their nourishment and deepen my understanding of research concepts.\\r\\nWhen introduced to YSG at the first info session, it has always piqued my interest. Its concept is young researchers, who are underrated by their age, mentoring and fostering younger ones whose ambitions cannot be tamed by simple and less competitive programs. Young researchers, just like myself then, do not need only mentoring and telling them where they are wrong anyone can do this. They are to be shown some care, and that we are their seniors and understand more and have more experience than them by far. Only then will they trust us and show some respect and follow our advice.\\r\\nNow, the real work will start. Using the previously stated condition of YSG, the young researchers will reach their potential little by little until they submit their final paper, hoping for the highest grades, as the environment pushes them to it.\\r\\nOne example of this was in my sophomore year, when one of the teams was lagging, searching for the location, while most of the teams started searching for the materials. They faced this problem after being hindered by searching on normal websites, not on professional search engines such as Google Scholar. When their leader asked for help, I simply did not tell him the way directly but made them understand how I reached it and how anyone can reach it by dividing their aim into steps and searching step by step until they reach that one keyword they are going to stick on their search bar, as it indicates perfectly their aim.\",\"second-essay\":\"Dear fellows,\\r\\nWe saw a great potential in you as a promising researcher, so by wasting it you are failing our expectation. In the same time, there were people who was eager to get accepted and take your place. So, seize the opportunity we gave you while you still have the chance to do so. And remember, deadlines are not here because the time is limited, but to teach you discipline. Hope this will not happen again forcing us to take unnecessary actions. \",\"third-essay\":\"I completed Writing in sciences course provided by Stanford university.\\r\\nI completed English for Science, Engineering, and Mathematics course provided by University of Penssylvania.\\r\\n I completed Chemical Biology: Concepts and Technique course on Coursera, provided by Geneva university.\\r\\nI received an honorable mention in the International Biology Bowl competition.  \\r\\nI am currently a mentor at STEM October biology club research track.\\r\\nI am currently finalizing a systematic review paper about the hyperparathyroidism in men and its broad aspects of symptoms and potential treatment techniques for it probable complications.\\r\\nI have wrote a paper about the relation between different kinds of diet and its affect on absorption of vitamins and minerals and directly affecting the rate of cellular respiration. \\r\\nI am currently enrolled in the International Young Researchers Conference medicine and research summer program, Summer 2025 cohort. \\r\\nI am currently a mentor of organic chemistry at STEM October Chemistry club.\\r\\nI finished Human anatomy and medical terminology fundamentals course.\\r\\nI completed Visualizing the Living Body: Diagnostic Imaging provided by Yale university.\",\"hours_commitment\":\"6\",\"time_blocks\":\"2 weeks in the middle of June and 1 week on the first of August.\",\"hear_about\":\"school\",\"edit_mode\":\"1\",\"application_id\":66}', '{\"research_files\":[],\"commented_files\":[{\"name\":\"Copy of A Comparative Study of the Perceived Stress Levels and Sources of Stress(1).docx\",\"path\":\"uploads\\/SYSJ060\\/final\\/Copy_of_A_Comparative_Study_of_the_Perceived_Stress_Levels_and_Sources_of_Stress_1_.docx\",\"size\":75062,\"type\":\"application\\/vnd.openxmlformats-officedocument.wordprocessingml.document\"}],\"additional_files\":[]}', '2025-07-05 19:06:09'),
('SYSJ061', '{\"full-name\":\"Nadeen Mahmoud\",\"email-address\":\"nad.hossam05@gmail.com\",\"contact-number\":\"01093433316\",\"country\":\"Egypt\",\"birth-date\":\"2005-02-18\",\"institution\":\"University of Alexandria Faculty of Medicine \",\"grade-year\":\"g\",\"gpa\":\"g\",\"interest\":[\"Aerospace Engineering\"],\"interest_ratings\":{\"Aerospace Engineering\":\"5\"},\"grade-previous\":\"vf\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '[]', '2025-06-18 14:12:51'),
('SYSJ063', '{\"full-name\":\"Nancy William \",\"email-address\":\"nancynabil7774@gmail.com\",\"contact-number\":\"+201204486684\",\"country\":\"Egypt \",\"gender\":\"female\",\"birth-date\":\"2004-10-20\",\"institution\":\"Faculty of agricultural \",\"grade-year\":\"\",\"gpa\":\"\",\"interest\":[\"\"],\"grade-previous\":\"\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours_commitment\":\"5\",\"time_blocks\":\"Anytime \",\"hear_about\":\"Instagram \"}', '{\"commented_files\":[],\"research_files\":[{\"name\":\"admission-letter (1).pdf\",\"path\":\"uploads\\/SYSJ063\\/drafts\\/admission-letter__1_.pdf\",\"size\":166364,\"type\":\"application\\/pdf\"}],\"additional_files\":[{\"name\":\"Health Certificate-1.pdf\",\"path\":\"uploads\\/SYSJ063\\/drafts\\/Health_Certificate-1.pdf\",\"size\":299291,\"type\":\"application\\/pdf\"}]}', '2025-07-04 00:12:13'),
