('SYSJ068', '{\"full-name\":\"Rania Massoud\",\"email-address\":\"am7421051@gmail.com\",\"contact-number\":\"01276726870\",\"country\":\"Egypt\",\"gender\":\"female\",\"birth-date\":\"2004-12-24\",\"institution\":\"Faculty of Medicine, Fayoum University\",\"grade-year\":\"Second year \",\"gpa\":\"3,3 (-A)\",\"interest\":[\"Medicine & Public Health,Psychology\"],\"interest_ratings\":{\"Medicine & Public Health\":\"5\",\"Psychology\":\"6\"},\"grade-previous\":\"Not yet\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '[]', '2025-06-18 15:07:10'),
('SYSJ069', '{\"full-name\":\"Mostafa Mohamed\",\"email-address\":\"mostafamohamedkamel3900@gmail.com\",\"contact-number\":\"01033486585\",\"country\":\"Egypt\",\"birth-date\":\"2009-01-01\",\"institution\":\"STEM High School for Boys - 6th of October\",\"grade-year\":\"Grade 10\",\"gpa\":\"4.00\",\"interest\":[\"Robotics\"],\"interest_ratings\":{\"Robotics\":\"7\"},\"grade-previous\":\"\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '[]', '2025-06-18 15:10:59'),
('SYSJ070', '{\"full-name\":\"Yousef Habib \",\"email-address\":\"yousef7abib2008@gmail.com\",\"contact-number\":\"01002504867\",\"country\":\"Egypt\",\"gender\":\"male\",\"birth-date\":\"2008-10-01\",\"institution\":\"STEM High School For Boys-6th October \",\"grade-year\":\"11\",\"gpa\":\"3.8\",\"interest\":[\"Computer Science\",\"Engineering (not Aerospace Engineering)\",\"Mathematics\",\"Physics & Astrophysics\"],\"interest_ratings\":{\"Computer Science\":\"9\",\"Engineering (not Aerospace Engineering)\":\"5\",\"Mathematics\":\"6\",\"Physics & Astrophysics\":\"10\"},\"grade-previous\":\"B+ ,  , B+ , A \",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\",\"hours_commitment\":\"\",\"time_blocks\":\"\",\"hear_about\":\"\"}', '{\"research_files\":[],\"commented_files\":[],\"additional_files\":[]}', '2025-07-05 19:12:03'),
('SYSJ071', '{\"full-name\":\"\",\"email-address\":\"\",\"contact-number\":\"\",\"country\":\"\",\"gender\":\"female\",\"birth-date\":\"1999-04-18\",\"institution\":\"Benha University \",\"grade-year\":\"2023\",\"gpa\":\"3.03 out of 4\",\"interest\":[\"Chemistry\"],\"interest_ratings\":{\"Chemistry\":\"5\"},\"grade-previous\":\"3.03 out of 4\",\"first-essay\":\"Mentorship in scientific research is not merely about transmitting knowledge\\u2014its about cultivating curiosity, resilience, and independent thinking. It requires a deep command of scientific principles and, just as importantly, the empathy and communication skills to help students navigate uncertainty with confidence and purpose.\\r\\n\\r\\nMy journey in scientific research has been shaped by both inquiry and instruction. Academically, Ive engaged with chemistry at an advanced level when i graduated from the faculty of science, contributing to my undergraduate research about drug delivery by nanoparticles.\\r\\n\\r\\nOne of my core mentoring goals is to foster self-efficacy in early-stage researchers. I emphasize process over perfection, encouraging them to formulate hypotheses, embrace iteration, and see failure as part of discovery. I hope to raise not just competent researchers, but confident thinkers.\\r\\n\\r\\n YSJ\\u2019s emphasis on ethical inquiry, interdisciplinary thinking, and inclusive learning provides fertile ground to mold students not just technically, but philosophically. Its student-centered environment and culture of close supervision are exactly the kind of framework I believe amplifies mentor impact. \\r\\n\\r\\nThrough my experiences, I\\u2019ve come to appreciate that mentorship is as much about listening as teaching. I look forward to continuing that journey at YSJ, where scientific excellence is pursued not in isolation, but in community.\",\"second-essay\":\"Hey Team 123,\\r\\nI wanted to check in regarding the research idea proposal it was due next week, and we haven\\u2019t received it from your group yet. I understand things can get busy, but this stage is essential for moving the project forward and locking in your direction.\\r\\n\\r\\nPlease make it a priority to finalize and submit your proposal within the next 24 hours. If youre facing any roadblocks, whether conceptual or logistic Im here to help. Just reach out, and we can troubleshoot together.\",\"third-essay\":\"\",\"hours\":\"10\",\"time-blocks\":\"From June\",\"hear\":\"Social media \"}', '[]', '2025-06-18 16:07:07'),
('SYSJ072', '{\"full-name\":\"Fatma Elhosseiny\",\"email-address\":\"fm137510@gmail.com\",\"contact-number\":\"+20 1203441978\",\"country\":\"Egypt\",\"gender\":\"female\",\"birth-date\":\"2008-11-13\",\"institution\":\"Maadi STEM School for Girls\",\"grade-year\":\"12\",\"gpa\":\"3.75\",\"interest\":[\"Physics & Astrophysics\"],\"interest_ratings\":{\"Physics & Astrophysics\":\"8\"},\"grade-previous\":\"B+\",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '[]', '2025-06-18 15:48:10'),
