('SYSJ093', '{\"full-name\":\"Yassmin Ahmed \",\"email-address\":\"yassmin.1124610@stemmaadi.moe.edu.eg\",\"contact-number\":\"01040262144\",\"country\":\"Egypt\",\"birth-date\":\"2010-05-02\",\"institution\":\"Maadi STEM School For Girls \",\"grade-year\":\"G11\",\"gpa\":\"0.4 (A total)\",\"interest\":[\"Biology,Chemistry,Environmental Science\"],\"interest_ratings\":{\"Biology\":\"5\",\"Chemistry\":\"5\",\"Environmental Science\":\"5\"},\"grade-previous\":\"Biology A \\\\ Chemistry A \\\\ Enviromental Science N\\\\A \",\"first-essay\":\"\",\"second-essay\":\"\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '[]', '2025-06-18 23:24:10'),
('SYSJ094', '{\"full-name\":\"yara\",\"email-address\":\"yarasaberhasan23@gmail.com\",\"contact-number\":\"01140858357\",\"country\":\"Egypt\",\"gender\":\"female\",\"birth-date\":\"2008-01-23\",\"institution\":\"Giza\",\"grade-year\":\"grade 11\",\"gpa\":\"3.8\",\"interest\":[\"Computer Science,Engineering (not Aerospace Engineering),Mathematics\"],\"interest_ratings\":{\"Computer Science\":\"3\",\"Engineering (not Aerospace Engineering)\":\"6\",\"Mathematics\":\"9\"},\"grade-previous\":\"computer science c+, mathematics B+\",\"first-essay\":\"jdncnc\",\"second-essay\":\"nfncnc\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '[]', '2025-06-20 14:54:52'),
('SYSJ095', '{\"full-name\":\"Wafaa Amr Elmaghraby\",\"email-address\":\"wafaa.elmaghraby123@gmail.com\",\"contact-number\":\"+201064262191\",\"country\":\"Egypt\",\"gender\":\"female\",\"birth-date\":\"2007-09-30\",\"institution\":\"Martyr Ahmed Hasan Ghonem High School For Girls\",\"grade-year\":\"G12\",\"gpa\":\"4\",\"interest\":[\"Engineering (not Aerospace Engineering)\",\"Environmental Science\"],\"interest_ratings\":{\"Engineering (not Aerospace Engineering)\":\"9\",\"Environmental Science\":\"9\"},\"grade-previous\":\"N\\/A\",\"first-essay\":\"Mentorship in scientific research requires a comprehensive understanding of the concepts and the ability to motivate and direct students as they go through their difficulties.\\r\\nI truly believe that because I have experienced its meaning through my own research journey. I started working on sustainable solutions in materials science, focusing on geopolymer concrete as an eco friendly native to cement.\\r\\nDuring my work for competitions like EISTF, ITC, and UGRF, I learned that research is not just about technical results, but also about leading and supporting others when challenges arise.\\r\\nOne of my proudest moments was during my ITC project when my teammates struggled to understand the chemical reactions behind our geopolymer mix. Instead of working alone, I broke down the concepts, explained the role of activators step by step, and encouraged open discussions. Seeing them grow more confident and able to interpret lab results was incredibly rewarding.\\r\\nMy goal is not just to advance my research but to share what I know and build a supportive community around me. I want young researchers to feel that it\\u2019s okay to fail, to ask questions, and to think creatively.\\r\\nYSJ\\u2019s high standards in mentorship, research ethics, and collaboration fit perfectly with what I believe in. I hope to develop my leadership skills further at YSJ so I can motivate future students to find excitement in complex problems and contribute to real world solutions.\",\"second-essay\":\"Hey Team 123,\\r\\nI noticed that your Research Idea Proposal hasn\\u2019t been submitted yet, and the deadline has already passed. I know everyone\\u2019s balancing a lot right now, but meeting deadlines is crucial not just for your own progress, but for the entire team\\u2019s workflow.\\r\\nPlease  me today with your current status. If you\\u2019re facing any challenges whether it\\u2019s finalizing your idea, dividing tasks, or just feeling stuck I\\u2019m here to help you get back on track\\r\\nYSJ Senior Researcher\",\"third-essay\":\"\",\"hours_commitment\":\"\",\"time_blocks\":\"\",\"hear_about\":\"\"}', '{\"research_files\":[],\"commented_files\":[],\"additional_files\":[]}', '2025-07-05 19:58:59'),
('SYSJ097', '{\"full-name\":\"Maria Halimeh\",\"email-address\":\"mariahalimeh.writer@gmail.com\",\"contact-number\":\"01100523446\",\"country\":\"Syria\",\"birth-date\":\"1998-03-21\",\"institution\":\"Cairo University faculty of Pharmacy \",\"grade-year\":\"Graduate class 2022\",\"gpa\":\"Very good\",\"interest\":[\"Medicine & Public Health\"],\"interest_ratings\":{\"Medicine & Public Health\":\"5\"},\"grade-previous\":\"Very good and excellent \",\"first-essay\":\"Ghhh\",\"second-essay\":\"Bbbh\",\"third-essay\":\"\",\"hours\":\"\",\"time-blocks\":\"\",\"hear\":\"\"}', '[]', '2025-06-19 01:16:27');
